// ============================================================
// PostNL CSV Generatie — Plug&Pay Order → PostNL import
// ============================================================
// AANPASSEN: Als Plug&Pay andere veldnamen gebruikt, pas de
// veldnamen hieronder aan. Check de n8n execution-log om
// de exacte JSON-structuur van de Plug&Pay API-response te zien.
// ============================================================

const raw = $json;

// Plug&Pay v2 API response zit in .data
const order = raw.data || raw;

// Adresgegevens — meerdere veldnamen als fallback
const billing = order.billing_address || order.billing || order.customer || {};
const shipping = order.shipping_address || order.delivery_address || billing;

const firstName = (shipping.first_name || billing.first_name || '').trim();
const lastName  = (shipping.last_name  || billing.last_name  || '').trim();
const fullName  = [firstName, lastName].filter(Boolean).join(' ');

const street      = (shipping.street || billing.street || '').trim();
const houseNumber = (shipping.house_number || billing.house_number ||
                     shipping.street_number || billing.street_number || '').toString().trim();
const suffix      = (shipping.house_number_suffix || billing.house_number_suffix || '').trim();
const postalCode  = (shipping.postal_code || billing.postal_code ||
                     shipping.zipcode || billing.zipcode || '').replace(/\s/g, '').toUpperCase();
const city        = (shipping.city || billing.city || '').trim();
const country     = (shipping.country || billing.country ||
                     shipping.country_code || billing.country_code || 'NL').trim().toUpperCase();
const email       = (billing.email || order.email ||
                     (order.customer && order.customer.email) || '').trim();
const phone       = (billing.phone || billing.phone_number ||
                     shipping.phone || '').trim();
const orderId     = String(order.id || order.order_id || $json.triggerable_id || 'onbekend');

// ============================================================
// PostNL CSV kolommen (puntkomma-gescheiden, UTF-8)
// Productcode 3085 = Pakket NL (standaard)
// Productcode 2928 = Brievenbuspakket
// AANPASSEN: wijzig de productcode naar wat je gebruikt
// ============================================================
const PRODUCTCODE = '3085';

const headers = [
  'Naam',
  'Bedrijfsnaam',
  'Straat',
  'Huisnummer',
  'Toevoeging',
  'Postcode',
  'Woonplaats',
  'Land',
  'E-mailadres',
  'Telefoonnummer',
  'Kenmerk',
  'Productcode'
].join(';');

// Veiligheidscheck: verwijder puntkomma's uit waarden (PostNL-vereiste)
const safe = (val) => String(val || '').replace(/;/g, '').substring(0, 35);

const row = [
  safe(fullName),
  safe(''),
  safe(street),
  safe(houseNumber),
  safe(suffix),
  safe(postalCode),
  safe(city),
  safe(country),
  safe(email),
  safe(phone),
  safe('Bestelling ' + orderId),
  PRODUCTCODE
].join(';');

const csvContent = headers + '\n' + row;

// Validatie — log een waarschuwing als verplichte velden leeg zijn
const missing = [];
if (!fullName)    missing.push('Naam');
if (!street)      missing.push('Straat');
if (!houseNumber) missing.push('Huisnummer');
if (!postalCode)  missing.push('Postcode');
if (!city)        missing.push('Woonplaats');

if (missing.length > 0) {
  console.log('WAARSCHUWING: Ontbrekende verplichte velden: ' + missing.join(', '));
  console.log('Volledige Plug&Pay response:', JSON.stringify(raw, null, 2));
}

// Binary data voor e-mailbijlage
return [{
  json: {
    orderId,
    customerName: fullName,
    city,
    postalCode,
    missingFields: missing,
    csvContent
  },
  binary: {
    attachment: {
      data: Buffer.from(csvContent, 'utf-8').toString('base64'),
      mimeType: 'text/csv',
      fileName: 'postnl-bestelling-' + orderId + '.csv',
      fileExtension: 'csv'
    }
  }
}];

